+#[test]
+fn pidfd_send_signal_invalid_pidfd_sets_ebadf_like_host() {
+    unsafe {
+        *__errno_location() = 0;
+    }
+    let rc = unsafe { pidfd_send_signal(-1, 0, ptr::null(), 0) };
+    let err = unsafe { *__errno_location() };
+
+    assert_eq!(rc, -1);
+    assert_eq!(
+        err,
+        libc::EBADF,
+        "unexpected errno from pidfd_send_signal(-1): {err}"
+    );
+}
